import{_ as e,o as n,c as r,ag as a}from"./chunks/framework.5wcOFaQl.js";const p=JSON.parse('{"title":"Software Development, Web Development & Yuanbao 💻🌐💰","description":"","frontmatter":{},"headers":[],"relativePath":"skills/dev-web-yuanbao.md","filePath":"skills/dev-web-yuanbao.md"}'),s={name:"skills/dev-web-yuanbao.md"};function i(d,t,o,l,h,g){return n(),r("div",null,[...t[0]||(t[0]=[a(`<h1 id="software-development-web-development-yuanbao-💻🌐💰" tabindex="-1">Software Development, Web Development &amp; Yuanbao 💻🌐💰 <a class="header-anchor" href="#software-development-web-development-yuanbao-💻🌐💰" aria-label="Permalink to &quot;Software Development, Web Development &amp; Yuanbao 💻🌐💰&quot;">​</a></h1><hr><h2 id="📊-auf-einen-blick" tabindex="-1">📊 Auf einen Blick <a class="header-anchor" href="#📊-auf-einen-blick" aria-label="Permalink to &quot;📊 Auf einen Blick&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kategorie</th><th>Skills</th><th>Kurzbeschreibung</th></tr></thead><tbody><tr><td>💻 <strong>Software Dev</strong></td><td>13 Skills</td><td>Debugging, TDD, Code-Review, Plans, Paketierung &amp; mehr</td></tr><tr><td>🌐 <strong>Web Development</strong></td><td>2 Skills</td><td>VitePress-Seiten, GitHub Pages Deployment, Fan-Wiki</td></tr><tr><td>💰 <strong>Yuanbao</strong></td><td>1 Skill</td><td>Gruppen-Interaktion auf Yuanbao (元宝)</td></tr></tbody></table><hr><h2 id="🧩-icon-ubersicht" tabindex="-1">🧩 Icon-Übersicht <a class="header-anchor" href="#🧩-icon-ubersicht" aria-label="Permalink to &quot;🧩 Icon-Übersicht&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">💻 Software Development</th><th style="text-align:center;">🌐 Web Development</th><th style="text-align:center;">💰 Yuanbao</th></tr></thead><tbody><tr><td style="text-align:center;">🐛 Debugging</td><td style="text-align:center;">📖 VitePress</td><td style="text-align:center;">💬 Gruppen</td></tr><tr><td style="text-align:center;">🧪 TDD</td><td style="text-align:center;">🚀 GitHub Pages</td><td style="text-align:center;">👥 @Mentions</td></tr><tr><td style="text-align:center;">📋 Plans</td><td style="text-align:center;">🎮 Fan-Wiki</td><td style="text-align:center;">ℹ️ Info</td></tr><tr><td style="text-align:center;">🔍 Code-Review</td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">📦 Paketierung</td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr></tbody></table><hr><h2 id="💻-software-development" tabindex="-1">💻 Software Development <a class="header-anchor" href="#💻-software-development" aria-label="Permalink to &quot;💻 Software Development&quot;">​</a></h2><p>Skills für Entwickler: Debugging, TDD, Code-Review, Plans und mehr.</p><table tabindex="0"><thead><tr><th>#</th><th>Skill</th><th>Auslöser</th><th>⚡ Features</th><th>⚠️ Fallstricke</th></tr></thead><tbody><tr><td>1</td><td><strong>debugging-hermes-tui-commands</strong></td><td>Hermes TUI Slash-Befehle debuggen</td><td>TUI-Debugging, Slash-Command-Analyse</td><td>Terminal-Output vs TUI-Interaktion beachten</td></tr><tr><td>2</td><td><strong>flask-script-dashboard</strong></td><td>&quot;Dashboard für Python-Skript&quot;, &quot;Web-GUI für CLI-Tool&quot;</td><td>Python-Skripte wrappen (1:1!) als Flask-Dashboard</td><td>Original-Skripte <strong>nie verändern</strong> – 1:1-Kopie-Prinzip</td></tr><tr><td>3</td><td><strong>game-guide-vitepress</strong></td><td>Spielguide/Compendium</td><td>VitePress-Webseite für Spiele-Guides</td><td>Große Content-Mengen erfordern Strukturplanung</td></tr><tr><td>4</td><td><strong>hermes-agent-skill-authoring</strong></td><td>Eigene SKILL.md schreiben</td><td>Frontmatter, Validator, Struktur</td><td>Frontmatter-Syntax strikt einhalten</td></tr><tr><td>5</td><td><strong>node-inspect-debugger</strong></td><td>Node.js debuggen</td><td><code>--inspect</code> + Chrome DevTools Protocol</td><td>Chrome DevTools-Verbindung erforderlich</td></tr><tr><td>6</td><td><strong>plan</strong></td><td>&quot;Plan erstellen&quot;, &quot;Task-Liste&quot;, &quot;Vorgehen planen&quot;</td><td>Markdown-Plan schreiben, <strong>keine Ausführung</strong></td><td>Nur Plan – keine Code-Generierung</td></tr><tr><td>7</td><td><strong>python-debugpy</strong></td><td>&quot;Python Debugger&quot;, &quot;pdb&quot;, &quot;debugpy&quot;</td><td>pdb REPL + debugpy remote (DAP), Breakpoints, Variables</td><td>Remote-Verbindung nötig für debugpy</td></tr><tr><td>8</td><td><strong>python-script-to-package</strong></td><td>Verstreute Python-Skripte</td><td>In installierbares Paket umstrukturieren</td><td>Abhängigkeiten sauber definieren</td></tr><tr><td>9</td><td><strong>requesting-code-review</strong></td><td>&quot;Review meinen Code&quot;, &quot;Security-Check&quot;</td><td>Security-Scan, Quality Gates, Auto-Fix</td><td>Vor <strong>jedem Commit</strong> ausführen</td></tr><tr><td>10</td><td><strong>subagent-driven-development</strong></td><td>Implementierungspläne</td><td>Unabhängige Sub-Agenten ausführen</td><td>Sub-Agenten-Koordination komplex</td></tr><tr><td>11</td><td><strong>systematic-debugging</strong></td><td>&quot;Das Programm stürzt ab&quot;, &quot;Stacktrace&quot;, &quot;Debug den Fehler&quot;</td><td>7-Schritte-System: Reproduzieren → Isolieren → Analysieren → Hypothese → Fix → Testen → Regression</td><td>Schritt 1 (Reproduzieren) nicht überspringen!</td></tr><tr><td>12</td><td><strong>test-driven-development</strong></td><td>&quot;TDD&quot;, &quot;Test first&quot;, &quot;RED-GREEN-REFACTOR&quot;</td><td>Test-first-Ansatz mit 3 Phasen</td><td>Disziplin für RED-Phase nötig</td></tr><tr><td>13</td><td><strong>web-based-admin-panel</strong></td><td>Webbasiertes Server-Admin-Panel</td><td>Webmin-ähnliches Dashboard</td><td>Sicherheitsrichtlinien beachten</td></tr></tbody></table><hr><h3 id="🎯-wichtige-skills-im-detail" tabindex="-1">🎯 Wichtige Skills im Detail <a class="header-anchor" href="#🎯-wichtige-skills-im-detail" aria-label="Permalink to &quot;🎯 Wichtige Skills im Detail&quot;">​</a></h3><hr><h4 id="🐛-systematic-debugging" tabindex="-1">🐛 systematic-debugging <a class="header-anchor" href="#🐛-systematic-debugging" aria-label="Permalink to &quot;🐛 systematic-debugging&quot;">​</a></h4><p><strong>Auslöser:</strong> „Das Programm stürzt ab&quot;, „Stacktrace&quot;, „Debug den Fehler&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>7-stufiges Debugging-System: Reproduzieren → Minimalbeispiel → Logs/Stacktrace → Hypothese → Fix → Test → Regression. Strukturiertes Vorgehen bei <strong>jedem</strong> Bug oder Test-Fehler.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ Schritt 1 überspringen („Den Fehler kenne ich schon&quot;) → führe ihn immer reproduzierbar aus. ❌ Keine Hypothese vor dem Fix → Rate-Fixes vermeiden. ❌ Regression-Tests vergessen → alter Code kann kaputtgehen.</td></tr></tbody></table><p><strong>Workflow:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 🔄 Fehler reproduzieren</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>2. ✂️ Minimales Beispiel isolieren</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>3. 📋 Logs/Stacktrace analysieren</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>4. 💡 Hypothese bilden</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>5. 🔧 Fix implementieren</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>6. ✅ Testen, ob Fix wirkt</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>7. 🔁 Regression-Tests laufen lassen</span></span></code></pre></div><hr><h4 id="🧪-test-driven-development" tabindex="-1">🧪 test-driven-development <a class="header-anchor" href="#🧪-test-driven-development" aria-label="Permalink to &quot;🧪 test-driven-development&quot;">​</a></h4><p><strong>Auslöser:</strong> „TDD&quot;, „Test first&quot;, „RED-GREEN-REFACTOR&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>Erzwingt Test-first-Ansatz. Drei klar getrennte Phasen: RED (Test schreiben, der fehlschlägt) → GREEN (Code schreiben, der Test besteht) → REFACTOR (Code verbessern, Tests bleiben grün).</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ RED-Phase überspringen und direkt Code schreiben → das ist TDD nicht. ❌ REFACTOR-Phase auslassen → Code-Qualität leidet. ❌ Zu große Tests in RED → inkrementelles Arbeiten unmöglich.</td></tr></tbody></table><p><strong>Zyklus:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│   🔴 RED        →    🟢 GREEN      →    🔵 REFACTOR  │</span></span>
<span class="line"><span>│   Test          →    Code          →    Verbessern   │</span></span>
<span class="line"><span>│   schreiben     →    schreiben     →    + Test grün  │</span></span>
<span class="line"><span>│   (failt)       →    (besteht)     →    (bleibt grün)│</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><hr><h4 id="📋-writing-plans-plan" tabindex="-1">📋 writing-plans &amp; plan <a class="header-anchor" href="#📋-writing-plans-plan" aria-label="Permalink to &quot;📋 writing-plans &amp; plan&quot;">​</a></h4><p><strong>Auslöser:</strong> „Plan erstellen&quot;, „Task-Liste&quot;, „Vorgehen planen&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th><code>plan</code></th><th><code>writing-plans</code></th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>Schreibt Markdown-Plan, <strong>keine Ausführung</strong>. Reiner Plan-Modus.</td><td>Erstellt Task-Listen mit Dateipfaden, Code-Schnipseln und detaillierten Schritten.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ Erwartet, dass der Plan auch ausgeführt wird → <code>plan</code> führt <strong>nie</strong> Code aus.</td><td>❌ Zu abstrakte Tasks → besser kleine, konkrete Einzelschritte. ❌ Pfade vergessen → immer Dateipfade angeben.</td></tr></tbody></table><hr><h4 id="🔍-requesting-code-review" tabindex="-1">🔍 requesting-code-review <a class="header-anchor" href="#🔍-requesting-code-review" aria-label="Permalink to &quot;🔍 requesting-code-review&quot;">​</a></h4><p><strong>Auslöser:</strong> „Review meinen Code&quot;, „Security-Check&quot;, „Code-Qualität&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>Automatisierte Pre-Commit-Review: Security-Scan auf bekannte Schwachstellen, Quality Gates (Linter, Type-Checker), Style-Prüfung, Auto-Fix für einfache Probleme.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ Review erst nach dem Commit → zu spät, vorher ausführen! ❌ Auto-Fix nicht nachprüfen → maschinelle Fixes können Kontext verlieren.</td></tr></tbody></table><hr><h4 id="🐍-python-debugpy" tabindex="-1">🐍 python-debugpy <a class="header-anchor" href="#🐍-python-debugpy" aria-label="Permalink to &quot;🐍 python-debugpy&quot;">​</a></h4><p><strong>Auslöser:</strong> „Python Debugger&quot;, „pdb&quot;, „debugpy&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>Zwei Debug-Modi: <code>pdb</code> (klassische REPL) und <code>debugpy</code> (DAP-Protokoll für Remote-Debugging). Step-Debugging, Breakpoints, Variable-Inspection.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ <code>debugpy</code> braucht eine laufende DAP-Client-Verbindung → ohne Remote-Gegenstelle startet der Prozess nicht. ❌ <code>pdb</code> blockt im Terminal → für CI/CD ungeeignet.</td></tr></tbody></table><hr><h4 id="🧪-flask-script-dashboard" tabindex="-1">🧪 flask-script-dashboard <a class="header-anchor" href="#🧪-flask-script-dashboard" aria-label="Permalink to &quot;🧪 flask-script-dashboard&quot;">​</a></h4><p><strong>Auslöser:</strong> „Dashboard für Python-Skript&quot;, „Web-GUI für CLI-Tool&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>Wrapt bestehende Python-Skripte ohne Änderung (1:1-Kopie-Prinzip) in ein Flask-Web-Dashboard. CLI-Argumente werden zu Web-Formular-Feldern.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ 1:1-Prinzip verletzen → Original-Skripte <strong>nie</strong> verändern! Immer Kopie wrappen. ❌ Keine Input-Validierung im Web-Formular → gefährliche CLI-Argumente filtern.</td></tr></tbody></table><hr><h2 id="🌐-web-development" tabindex="-1">🌐 Web Development <a class="header-anchor" href="#🌐-web-development" aria-label="Permalink to &quot;🌐 Web Development&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Skill</th><th>Auslöser</th><th>⚡ Features</th><th>⚠️ Fallstricke</th></tr></thead><tbody><tr><td>1</td><td><strong>vitepress-github-pages</strong></td><td>&quot;Neue VitePress-Seite&quot;, &quot;GitHub Pages Setup&quot;</td><td>VitePress-Projekt einrichten + deployen, CI/CD-Workflow</td><td>GitHub-Token/Berechtigungen für Actions nötig</td></tr><tr><td>2</td><td><strong>wwm-compendium</strong></td><td>&quot;WWM-Seite bearbeiten&quot;, &quot;Where Winds Meet&quot;</td><td>Fan-Wiki mit ~45 Seiten: Waffen, Bosse, Quests, Items</td><td>Content-Pflege bei Spiel-Updates</td></tr></tbody></table><hr><h3 id="🎯-vitepress-github-pages-detail" tabindex="-1">🎯 vitepress-github-pages (Detail) <a class="header-anchor" href="#🎯-vitepress-github-pages-detail" aria-label="Permalink to &quot;🎯 vitepress-github-pages (Detail)&quot;">​</a></h3><p><strong>Auslöser:</strong> „Neue VitePress-Seite&quot;, „GitHub Pages Setup&quot;, „Dokumentationsseite&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>Kompletter Workflow: Projekt initialisieren → Konfigurieren → Theme anpassen → CI/CD-Workflow (GitHub Actions) erstellen → Repository anlegen → Auf GitHub Pages deployen. Automatisches Deployment bei Push auf main.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ <code>base</code>-Path im VitePress-Config vergessen → Seiten werden nicht korrekt ausgeliefert. ❌ GitHub Actions-Token nicht gesetzt → Deployment schlägt fehl. ❌ Branch-Name falsch (main vs master) → CI/CD triggert nicht.</td></tr></tbody></table><p><strong>Workflow:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📝 Projekt initiieren → ⚙️ Konfigurieren → 🎨 Theme anpassen</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>🔄 CI/CD erstellen (GitHub Actions)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>📦 Repo anlegen → 🚀 push → 🌐 GitHub Pages</span></span></code></pre></div><hr><h3 id="🎮-wwm-compendium" tabindex="-1">🎮 wwm-compendium <a class="header-anchor" href="#🎮-wwm-compendium" aria-label="Permalink to &quot;🎮 wwm-compendium&quot;">​</a></h3><p><strong>Auslöser:</strong> „WWM-Seite bearbeiten&quot;, „Where Winds Meet&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>Fan-Wiki für Where Winds Meet (WWM). Basierend auf VitePress. Ca. 45 Seiten: Waffen, Bosse, Quests, Items, allgemeine Info. Gleiche Technik wie vitepress-github-pages.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ Veraltete Inhalte nach Spiel-Updates → regelmäßig prüfen. ❌ Große Bild-Dateien → Performance-Optimierung nötig.</td></tr></tbody></table><hr><h2 id="💰-yuanbao" tabindex="-1">💰 Yuanbao <a class="header-anchor" href="#💰-yuanbao" aria-label="Permalink to &quot;💰 Yuanbao&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Auslöser</th><th>⚡ Features</th><th>⚠️ Fallstricke</th></tr></thead><tbody><tr><td><strong>yuanbao</strong></td><td>&quot;Yuanbao-Gruppe&quot;, &quot;元宝&quot;, &quot;Mitglieder abfragen&quot;</td><td>Gruppen-Interaktion: Mitglieder @erwähnen, Gruppeninfo abfragen, Mitgliederliste holen</td><td>API-Rate-Limits beachten, chinesische Messaging-Plattform</td></tr></tbody></table><h3 id="details" tabindex="-1">Details <a class="header-anchor" href="#details" aria-label="Permalink to &quot;Details&quot;">​</a></h3><p><strong>Auslöser:</strong> „Yuanbao-Gruppe&quot;, „元宝&quot;, „Mitglieder abfragen&quot;</p><table tabindex="0"><thead><tr><th>Aspekt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>⚡ Features</strong></td><td>Ermöglicht Interaktion mit Yuanbao-Gruppen (元宝). Mitglieder @erwähnen, Gruppeninfo abfragen, Mitgliederliste abrufen. Yuanbao ist eine chinesische Messaging-Plattform.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>❌ Rate-Limits der Yuanbao-API → zu viele Anfragen in kurzer Zeit führen zur Drosselung. ❌ Chinesische Zeichenkodierung beachten → UTF-8 sicherstellen.</td></tr></tbody></table><hr><h2 id="📋-schnellubersicht-nach-kategorie" tabindex="-1">📋 Schnellübersicht nach Kategorie <a class="header-anchor" href="#📋-schnellubersicht-nach-kategorie" aria-label="Permalink to &quot;📋 Schnellübersicht nach Kategorie&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">💻 Software Dev</th><th style="text-align:right;">🌐 Web</th><th style="text-align:center;">💰 Yuanbao</th></tr></thead><tbody><tr><td style="text-align:left;">13 Skills</td><td style="text-align:right;">2 Skills</td><td style="text-align:center;">1 Skill</td></tr><tr><td style="text-align:left;">Debugging, TDD, Plans</td><td style="text-align:right;">VitePress, GitHub Pages</td><td style="text-align:center;">Gruppen-Management</td></tr><tr><td style="text-align:left;">Code-Review, Paketierung</td><td style="text-align:right;">Fan-Wiki (WWM)</td><td style="text-align:center;">@Mentions, Info</td></tr></tbody></table><hr><blockquote><p><strong>Tipp:</strong> Die wichtigsten Skills für den täglichen Gebrauch sind <strong>systematic-debugging</strong> (bei jedem Bug), <strong>test-driven-development</strong> (bei jeder neuen Funktion) und <strong>writing-plans</strong> (vor jeder Implementierung). Für Web-Projekte starte mit <strong>vitepress-github-pages</strong>.</p></blockquote>`,65)])])}const b=e(s,[["render",i]]);export{p as __pageData,b as default};
